import cron from 'node-cron';
import {
  wrappedSyncCarrierTracking,
} from './runner';

const scheduledJobs: cron.ScheduledTask[] = [];

export function configureScheduler(): void {
  scheduledJobs.push(
    cron.schedule('*/30 * * * *', async () => {
      await wrappedSyncCarrierTracking();
    }, {
      scheduled: true,
      timezone: process.env.TZ || 'UTC',
    })
  );
  console.log(`[scheduler] job_registered name=SyncCarrierTracking schedule=*/30 * * * * concurrency=1`);
}

export function startScheduler(): void {
  configureScheduler();
  console.log(`[scheduler] started job_count=${scheduledJobs.length}`);
}

export function stopScheduler(): void {
  for (const task of scheduledJobs) {
    task.stop();
  }
  scheduledJobs.length = 0;
  console.log('[scheduler] stopped');
}
